/**
 * Validates `requiredIf` conditions of a map/item's attributes against their siblings:
 * - the controlling attribute must exist as a sibling
 * - an attribute cannot reference itself
 * - neither the dependent nor the controlling attribute can be a key attribute
 *
 * @param attributes Map/Item attributes
 * @param path Path of the map/item in the related schema (string)
 * @return void
 */
export const checkRequiredIf = (attributes: Record<string, Schema>, path?: string): void => {
  for (const [attributeName, attribute] of Object.entries(attributes)) {
    const { requiredIf, key } = attribute.props

    if (requiredIf === undefined || requiredIf.length === 0) {
      continue
    }

    const attributePath = [path, attributeName].filter(Boolean).join('.')

    if (key) {
      throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
        message: `Invalid attribute at path '${attributePath}': 'requiredIf' cannot be used on key attributes.`,
        path: attributePath,
        payload: { attributeName }
      })
    }

    for (const { attribute: controllingAttributeName } of requiredIf) {
      if (controllingAttributeName === attributeName) {
        throw new DynamoDBToolboxError('schema.requiredIf.selfReference', {
          message: `Invalid attribute at path '${attributePath}': 'requiredIf' cannot reference the attribute itself.`,
          path: attributePath,
          payload: { attributeName }
        })
      }

      const controllingAttribute = attributes[controllingAttributeName]

      if (controllingAttribute === undefined) {
        throw new DynamoDBToolboxError('schema.requiredIf.unknownAttribute', {
          message: `Invalid attribute at path '${attributePath}': 'requiredIf' references unknown sibling attribute '${controllingAttributeName}'.`,
          path: attributePath,
          payload: { attributeName, controllingAttributeName }
        })
      }

      if (controllingAttribute.props.key) {
        throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
          message: `Invalid attribute at path '${attributePath}': 'requiredIf' cannot reference key attribute '${controllingAttributeName}'.`,
          path: attributePath,
          payload: { attributeName, controllingAttributeName }
        })
      }
    }
  }
}
