13	export const isRequired = (schema: Schema, mode: WriteMode): boolean => {
14	  switch (mode) {
15	    case 'put':
16	      return schema.props?.required !== 'never'
17	    case 'key':
18	    case 'update':
19	      return schema.props?.required === 'always'
20	  }
21	}
22	
23	const getValidator = (schema: Schema, mode: WriteMode) => {
24	  if (schema.props.key) {
25	    return schema.props.keyValidator
26	  }
27	
28	  switch (mode) {
29	    case 'key':
30	      return schema.props.keyValidator
31	    case 'put':
32	      return schema.props.putValidator
33	    case 'update':
34	      return schema.props.updateValidator
35	  }
36	}
