38	export const applyCustomValidation = (
39	  schema: Schema,
40	  inputValue: unknown,
41	  options: ParseAttrValueOptions = {}
42	): void => {
43	  const { mode = 'put', valuePath } = options
44	
45	  const customValidator = getValidator(schema, mode)
46	  if (customValidator !== undefined) {
47	    const validationResult = customValidator(inputValue, schema)
48	
