import type { Schema } from '~/schema/index.js'
import { isObject } from '~/utils/validation/isObject.js'

/**
 * Walks a map/item schema alongside its (already parsed) update input, collecting an
 * `attribute_exists` condition for every dependent attribute whose controlling sibling
 * is being set to one of its `requiredIf` trigger values. Only plain (non-extension) values
 * are matched against trigger values, since `$remove`/`$get`/... markers cannot be
 * meaningfully compared to static trigger values
 */
export const collectRequiredIfConditions = (
  schema: Schema,
  parsedValue: unknown,
  path: string[] = []
): SchemaCondition[] => {
  if ((schema.type !== 'map' && schema.type !== 'item') || !isObject(parsedValue)) {
    return []
  }

  const conditions: SchemaCondition[] = []

  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
    const { requiredIf } = attribute.props

    if (requiredIf !== undefined && requiredIf.length > 0) {
      for (const { attribute: controllingAttributeName, values } of requiredIf) {
        const controllingValue = parsedValue[controllingAttributeName]
        const isPlainValue = controllingValue === null || typeof controllingValue !== 'object'

        if (isPlainValue && values.includes(controllingValue)) {
          conditions.push({ attr: [...path, attributeName].join('.'), exists: true })
        }
      }
    }

    conditions.push(
      ...collectRequiredIfConditions(attribute, parsedValue[attributeName], [
        ...path,
        attributeName
      ])
    )
  }

  return conditions
}
