/**
 * Adds a `superRefine` enforcing `requiredIf` conditions of a map/item's attributes:
 * an issue is raised at the dependent attribute's path whenever a controlling sibling
 * is set to one of its trigger values but the dependent is absent
 */
export const withRequiredIf = (
  schema: MapSchema | ItemSchema,
  zodSchema: z.ZodTypeAny
): z.ZodTypeAny => {
  const conditions = Object.entries(schema.attributes).flatMap(([attributeName, attribute]) =>
    (attribute.props.requiredIf ?? []).map(condition => ({ attributeName, condition }))
  )

  if (conditions.length === 0) {
    return zodSchema
  }

  return zodSchema.superRefine((value: unknown, ctx: z.RefinementCtx) => {
    if (typeof value !== 'object' || value === null) {
      return
    }

    const record = value as Record<string, unknown>

    for (const { attributeName, condition } of conditions) {
      const controllingValue = record[condition.attribute]
      const isTriggered =
        controllingValue !== undefined && condition.values.includes(controllingValue)

      if (isTriggered && record[attributeName] === undefined) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          path: [attributeName],
          message: `Attribute '${attributeName}' is required.`
        })
      }
    }
  })
